def range_summary(nums):
    if not nums:
        return ''
    runs = []
    current, count = nums[0], 1
    for n in nums[1:]:
        if n == current + 1:
            count += 1
        else:
            runs.append((current, count))
            current, count = n, 1
    runs.append((current, count))
    return ', '.join('-'.join(map(str, r)) if c > 1 else str(r[0]) for r, c in runs)
